import{_ as r,M as a,p as s,q as l,R as t,t as e,N as i,a1 as n}from"./framework-5866ffd3.js";const d={},g=n('<h1 id="llm-应用层与生态" tabindex="-1"><a class="header-anchor" href="#llm-应用层与生态" aria-hidden="true">#</a> LLM 应用层与生态</h1><p>模型本身只能根据输入接龙输出，要让它在真实业务里有用，还需要在外围搭一层「<strong>调用约定 + 执行环境 + 知识来源</strong>」。本文聚焦这一层最常见的几个概念。</p><hr><h2 id="function-call-函数调用" tabindex="-1"><a class="header-anchor" href="#function-call-函数调用" aria-hidden="true">#</a> Function Call（函数调用）</h2><p>Function Call 指 LLM 在生成自然语言之外，还能按约定输出<strong>结构化数据</strong>（常见为 JSON），用来表示「要调用哪个外部函数、参数是什么」。借此可以把模型输出接到代码、HTTP API、数据库、脚本等，实现与真实系统的交互。</p><p>多数云厂商与开源栈会把它和 <strong>JSON Schema</strong>（或等价描述）绑定：先声明工具名与参数类型，模型只负责在合法集合里做选择并填参；真正执行仍由宿主程序完成。这是许多「工具使用 / Tool Use」方案的底层能力，Agent、MCP 等往往都建立在这层之上。</p><h2 id="agent" tabindex="-1"><a class="header-anchor" href="#agent" aria-hidden="true">#</a> Agent</h2><p>Agent 一般指 <strong>LLM + 工具 + 记忆 + 编排逻辑</strong> 构成的智能体：不局限于单次问答，而是能在多步里<strong>推理 → 选工具 → 执行 → 根据结果再推理</strong>，直到任务结束或达到终止条件。</p><p>与「只聊天」的用法相比，Agent 强调<strong>闭环</strong>：模型决定下一步动作，环境返回观测结果，再进入下一轮。记忆可以是会话摘要、向量检索、键值存储等形式，视产品而定。</p><h2 id="mcp-model-context-protocol" tabindex="-1"><a class="header-anchor" href="#mcp-model-context-protocol" aria-hidden="true">#</a> MCP（Model Context Protocol）</h2>',10),c={href:"https://modelcontextprotocol.io/",target:"_blank",rel:"noopener noreferrer"},h=t("strong",null,"开放协议",-1),p=n('<p>对模型侧而言，MCP 服务会提供<strong>能力声明</strong>：有哪些工具、每个工具的参数与说明。宿主在启动或连接时会拉取这份声明；用户提问时，模型在需要时发起工具调用，由 MCP 执行并返回结果，再用于生成最终回复。可以理解为：<strong>把一类集成方式标准化</strong>，便于同一套 MCP 被多个宿主复用。</p><h2 id="skill-技能" tabindex="-1"><a class="header-anchor" href="#skill-技能" aria-hidden="true">#</a> Skill（技能）</h2><p>Skill 常指<strong>可复用的技能说明</strong>：不限于「可调用的 API」，也可以描述<strong>规范、流程、约定、检查清单</strong>等。形式上多为 Markdown 等文档，开头常有<strong>摘要</strong>，正文展开细节与示例。</p><p>与 Agent 结合时，典型做法是：先只把各 Skill 的摘要注入上下文，让模型知道「有哪些技能」；当判断某条用户任务匹配某一 Skill 时，再<strong>按需加载</strong>该 Skill 全文，并按文档约束调整行为（例如优先用某类工具、遵守某套步骤）。这和单纯堆长提示词的区别在于：<strong>分层加载</strong>，节省上下文并减少干扰。</p><h2 id="rag-retrieval-augmented-generation" tabindex="-1"><a class="header-anchor" href="#rag-retrieval-augmented-generation" aria-hidden="true">#</a> RAG（Retrieval-Augmented Generation）</h2><p><strong>RAG（检索增强生成）</strong> 指在生成前，先从外部知识库检索出与问题相关的文档片段，把片段拼进 prompt 再交给 LLM 作答。它解决的是 LLM 自身的两个固有短板：训练数据有截止日期、参数化知识难以精确溯源。</p><p>典型流程：</p><ol><li><strong>索引阶段（离线）</strong>：把文档切片（chunking），用专门的 <strong>句子 Embedding 模型</strong>（如 BGE、text-embedding-3）把每片编码成稠密向量，存入向量数据库（如 Milvus、pgvector）。</li><li><strong>检索阶段（在线）</strong>：用同一个 Embedding 模型把用户问题编码成向量，按余弦相似度从向量库召回 Top-k 片段；常配合关键词检索（BM25）做混合召回，再用 reranker 精排。</li><li><strong>生成阶段</strong>：把召回的片段填入 prompt 模板（&quot;根据下面的资料回答……&quot;），交给 LLM 生成答复，可附上引用出处。</li></ol><blockquote><p>这里的 Embedding 是<strong>句子级别</strong>的，与 <code>tokenizer.md</code> 中模型内部的 token Embedding 不是一回事——前者是把整段文本压成一个向量用于检索，后者是模型查表得到的 token 向量。</p></blockquote><p><strong>与长上下文的关系</strong>：当文档总量远超模型窗口时，RAG 是绕开「真长上下文」的常用工程手段（见 <code>inference.md</code> 中的 上下文窗口）；即便模型支持 128K，先用 RAG 召回再生成往往仍是更经济、更可控的做法。</p>',10);function m(u,_){const o=a("ExternalLinkIcon");return s(),l("div",null,[g,t("p",null,[t("a",c,[e("MCP"),i(o)]),e(" 是一套"),h,e("，用来把「工具、资源、提示」等能力以标准方式暴露给支持 MCP 的客户端（如部分 IDE、桌面应用）。实现上常见为本地或远程进程，通过约定好的传输层与宿主通信。")]),p])}const f=r(d,[["render",m],["__file","llm.html.vue"]]);export{f as default};
